137	static void setjump(bfuncinfo *finfo, int pc, int dst)
138	{
139	    binstruction *p = be_vector_at(&finfo->code, pc);
140	    int offset = dst - (pc + 1);
141	    /* instruction edit jump destination */
142	    *p = (*p & ~IBx_MASK) | ISET_sBx(offset);
143	}
