145	static int isjumpbool(bfuncinfo *finfo, int pc)
146	{
147	    binstruction *p = be_vector_at(&finfo->code, pc);
148	    bopcode op = IGET_OP(*p);
149	
150	    if (op == OP_JMPT || op == OP_JMPF) {
151	        return 1;
152	    }
153	    return 0;
154	}
