156	static int get_jump(bfuncinfo *finfo, int pc)
157	{
158	    binstruction *i = be_vector_at(&finfo->code, pc);
159	    int offset = IGET_sBx(*i);
160	    return offset == NO_JUMP ? NO_JUMP : pc + 1 + offset;
161	}
