367	static int code_suffix(bfuncinfo *finfo, bopcode op, bexpdesc *e, int dst)
368	{
369	    dst = suffix_destreg(finfo, e, dst);
370	    if (dst > finfo->freereg) {
371	        dst = finfo->freereg;
372	    }
373	    codeABC(finfo, op, dst, e->v.ss.obj, e->v.ss.idx);
374	    return dst;
375	}
