505	/* compute binary expression and update e1 as result */
506	/* On exit, e1 is guaranteed to be ETREG, which may have been allocated */
507	static void binaryexp(bfuncinfo *finfo, bopcode op, bexpdesc *e1, bexpdesc *e2, int dst)
508	{
509	    if (dst < 0) { dst = finfo->freereg; }
510	    int src1 = exp2reg(finfo, e1, dst);  /* potentially force the target for src1 reg */
511	    int src2 = exp2anyreg(finfo, e2);
512	    dst = codedestreg(finfo, e1, e2, dst);
513	    codeABC(finfo, op, dst, src1, src2);
514	    e1->type = ETREG;
515	    e1->v.idx = dst; /* update register as output */
516	}
