558	/* Apply unary operator and return register number */
559	/* If input is register, change in place or allocate new register */
560	static void unaryexp(bfuncinfo *finfo, bopcode op, bexpdesc *e)
561	{
562	    int src = exp2anyreg(finfo, e);
563	    int dst = e->type == ETREG ? src : be_code_allocregs(finfo, 1);
564	    codeABC(finfo, op, dst, src, 0);
565	    e->type = ETREG;
566	    e->v.idx = dst;
567	}
